                      dbo.C_BUY_ITEMS.CB_ITEM_ID, dbo.C_BUY_ITEMS.ITEM_ID, dbo.C_BUY_ITEMS.QTY, dbo.C_BUY_ITEMS.UNIT_ID, dbo.C_BUY_ITEMS.UNIT_QTY, 
