SELECT     dbo.FUNDS.F_ID, dbo.FUNDS.F_NO, dbo.FUNDS.F_S_NO, dbo.FUNDS.F_B_NO, dbo.FUNDS.F_DATE, dbo.FUNDS.F_END_DATE, dbo.FUNDS.CUST_ID, 
                      dbo.FUNDS.BANK_CUST_ID, dbo.FUNDS.INVO_NO, dbo.FUNDS.SHIPMENT_TYPE, dbo.FUNDS.SHIPMENT_POLICY, dbo.FUNDS.ARRIVE_DATE, 
                      dbo.FUNDS.FUND_VALUE, dbo.FUNDS.BANK_ID, dbo.FUNDS.CURRENCY_ID, dbo.FUNDS.COVER_PERCENTEGE, dbo.FUNDS.ALL_COVER, dbo.FUNDS.RATE, 
                      dbo.FUNDS.ACC_DEBIT, dbo.FUNDS.ACC_CREDIT, dbo.FUNDS.NOTES, dbo.CUSTOMERS.CUST_NO, dbo.CUSTOMERS.CUST_NAME, 
                      dbo.BANKS_VIEW.BANK_NAME AS BANK_NAME_CUST, dbo.BANK2.BANK_NAME, dbo.CURRENCY.CURRENCY_DISC, dbo.FUNDS.F_STATUES, 
                      dbo.FUNDS.USERS_ID, dbo.USERS.FULL_NAME, dbo.FUNDS.F_UPDATE_DATE, dbo.ACCOUNTS.AC_NAME, ACCOUNTS_1.AC_NAME AS Expr1, 
                      dbo.FUNDS.F_OPEN_DATE, dbo.FUNDS.TRAN_NO, dbo.FUNDS.TRAN_BARNCH
FROM         dbo.BANK2 RIGHT OUTER JOIN
                      dbo.FUNDS ON dbo.BANK2.BANK_ID = dbo.FUNDS.BANK_ID LEFT OUTER JOIN
                      dbo.BANKS_VIEW ON dbo.FUNDS.BANK_CUST_ID = dbo.BANKS_VIEW.BANK_ID LEFT OUTER JOIN
                      dbo.ACCOUNTS AS ACCOUNTS_1 ON dbo.FUNDS.ACC_CREDIT = ACCOUNTS_1.AC_ID LEFT OUTER JOIN
                      dbo.ACCOUNTS ON dbo.FUNDS.ACC_DEBIT = dbo.ACCOUNTS.AC_ID LEFT OUTER JOIN
                      dbo.USERS ON dbo.FUNDS.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                      dbo.CURRENCY ON dbo.FUNDS.CURRENCY_ID = dbo.CURRENCY.CURRENCY_ID LEFT OUTER JOIN
                      dbo.CUSTOMERS ON dbo.FUNDS.CUST_ID = dbo.CUSTOMERS.CUST_ID;


-- dbo.GIVE_USER_ACESS_VIEW source

