-- dbo.GIVE_VIEW source

CREATE OR ALTER VIEW [dbo].[GIVE_VIEW]
AS
SELECT        dbo.GIVE.G_ID, dbo.GIVE.G_NO, dbo.GIVE.G_DATE, dbo.GIVE.G_VALUE, dbo.GIVE.CUST_ID, dbo.GIVE.COMM_ID, dbo.GIVE.COMM_PERCENT, dbo.GIVE.G_STATUES, dbo.GIVE.G_NOTE, dbo.GIVE.G_CHECK, 
                         dbo.GIVE.BANK_ID, dbo.GIVE.G_KIND, dbo.GIVE.PC_ID, dbo.GIVE.EXPENCES_ID, dbo.GIVE.G_UPDATE_DATE, USERS_1.FULL_NAME, EXPENCES_1.EXPENSE_DISC, dbo.CUSTOMERS.CUST_NO, 
                         dbo.CUSTOMERS.CUST_NAME, dbo.COMMISSIONER.COMM_NO, dbo.COMMISSIONER.COMM_NAME, dbo.BANKS.BANK_NAME, dbo.GIVE.G_DISC, dbo.BANKS.BANK_ACCOUNT, dbo.GIVE.USERS_ID, 
                         dbo.TYPE.T_NAME, dbo.GIVE.S_ID, dbo.GIVE.RATE, dbo.GIVE.CURRENCY_ID, dbo.CURRENCY.CURRENCY_DISC, dbo.EXPENCES.EXPENSE_DISC AS Expr1, dbo.EXPENCES.EXPENCES_TYPE, 
                         dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.GIVE.ACC_DEBIT, dbo.GIVE.ACC_CREDIT, dbo.CUSTOMERS.CAT9_ID, dbo.GIVE.G_DISCOUNT, 
                         dbo.GIVE.ACC_G_DISCOUNT_CREDIT, ACC_CREDIT_1.AC_NAME AS ACC_NAME_DISCOUNT_CREDIT, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, 
                         dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.LOGO, dbo.GIVE.TRAN_NO, dbo.GIVE.TRAN_BARNCH, dbo.CUSTOMERS.CAT8_ID, dbo.USERS.FULL_NAME AS Expr2, 
                         dbo.CUSTOMERS.BALANCE_HIDE, dbo.GIVE.G_TYPE
FROM            dbo.TRANS_CATEGORY RIGHT OUTER JOIN
                         dbo.CUSTOMERS RIGHT OUTER JOIN
                         dbo.BANKS RIGHT OUTER JOIN
                         dbo.GIVE INNER JOIN
                         dbo.COMMISSIONER ON dbo.GIVE.COMM_ID = dbo.COMMISSIONER.COMM_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.GIVE.A_USERS_ID = dbo.USERS.USERS_ID ON dbo.BANKS.BANK_ID = dbo.GIVE.BANK_ID ON dbo.CUSTOMERS.CUST_ID = dbo.GIVE.CUST_ID LEFT OUTER JOIN
                         dbo.EXPENCES AS EXPENCES_1 ON dbo.GIVE.EXPENCES_ID = EXPENCES_1.EXPENCES_ID LEFT OUTER JOIN
                         dbo.CURRENCY ON dbo.GIVE.CURRENCY_ID = dbo.CURRENCY.CURRENCY_ID LEFT OUTER JOIN
                         dbo.EXPENCES ON dbo.GIVE.EXPENCES_ID = dbo.EXPENCES.EXPENCES_ID ON dbo.TRANS_CATEGORY.TRAN_ID = dbo.GIVE.TRAN_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT AS ACC_CREDIT_1 ON dbo.GIVE.ACC_G_DISCOUNT_CREDIT = ACC_CREDIT_1.AC_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.GIVE.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.GIVE.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.USERS AS USERS_1 ON dbo.GIVE.USERS_ID = USERS_1.USERS_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.GIVE.G_STATUES = dbo.TYPE.T_ID;


