                         dbo.R_S_INVOICE.S_R_NOTE, dbo.R_S_INVOICE.S_R_UPDATE_DATE, USERS_1.FULL_NAME, dbo.COMMISSIONER.COMM_NO, dbo.COMMISSIONER.COMM_NAME, dbo.CUSTOMERS.CUST_NO, 
                         dbo.CUSTOMERS.CUST_NAME, dbo.R_S_INVOICE.CUST_NAME AS CUST_NAME1, dbo.R_S_INVOICE.BRANCH, dbo.TYPE.T_NAME, dbo.COMMISSIONER.COMM_PHONE, dbo.CUSTOMERS.CUST_ADRESS, 
                         dbo.CUSTOMERS.CUST_MAX_DEBIT, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.R_S_INVOICE.ACC_DEBIT, dbo.R_S_INVOICE.ACC_CREDIT, 
                         dbo.BANKS.BANK_NAME, dbo.R_S_INVOICE.BANK_ID, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.LOGO, 
                         dbo.R_S_INVOICE.TRAN_NO, dbo.R_S_INVOICE.TRAN_BARNCH, dbo.CUSTOMERS.EMP_SALARY, dbo.CUSTOMERS.CAT8_ID, dbo.R_S_INVOICE.A_USERS_ID, dbo.R_S_INVOICE.USER_IN_TIME, 
                         dbo.USERS.FULL_NAME AS FULL_A_NAME
