-- dbo.TAKE_VIEW source

CREATE OR ALTER VIEW [dbo].[TAKE_VIEW]
AS
SELECT        dbo.TAKE.T_ID, dbo.TAKE.T_NO, dbo.TAKE.T_DATE, dbo.TAKE.T_VALUE, dbo.TAKE.T_DISC, dbo.TAKE.CUST_ID, dbo.TAKE.COMM_ID, dbo.TAKE.COMM_PERCENT, dbo.TAKE.T_STATUES, dbo.TAKE.T_NOTE, 
                         dbo.TAKE.T_CHECK, dbo.TAKE.BANK_ID, dbo.TAKE.T_KIND, dbo.TAKE.PC_ID, dbo.TAKE.T_UPDATE_DATE, USERS_1.FULL_NAME, dbo.BANKS.BANK_NAME, dbo.BANKS.BANK_ACCOUNT, 
                         dbo.COMMISSIONER.COMM_NO, dbo.COMMISSIONER.COMM_NAME, dbo.CUSTOMERS.CUST_NO, dbo.CUSTOMERS.CUST_NAME, dbo.TAKE.CUST_NAME AS CUST_NAME_CASH, dbo.TAKE.USERS_ID, 
                         dbo.TYPE.T_NAME, dbo.TAKE.S_ID, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.TAKE.ACC_DEBIT, dbo.TAKE.ACC_CREDIT, dbo.CUSTOMERS.CAT9_ID,
                          dbo.TAKE.G_DISCOUNT, dbo.TAKE.ACC_T_DISCOUNT_DEBIT, ACC_DEBIT_1.AC_NAME AS ACC_NAME_DISCOUNT_DEBIT, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, 
                         dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.LOGO, dbo.TAKE.TRAN_NO, dbo.TAKE.TRAN_BARNCH, dbo.CUSTOMERS.CAT8_ID, dbo.TAKE.ACC_T_M_S_DEBIT_S1, 
                         dbo.TAKE.ACC_T_M_S_CREDIT_S1, ACC_DEBIT_2.AC_NAME AS ACC_T_M_S_DEBIT_NAME, ACC_CREDIT_1.AC_NAME AS ACC_T_M_S_CREDIT_NAME, dbo.TAKE.A_USERS_ID, 
                         dbo.USERS.FULL_NAME AS A_FULL_NAME, dbo.CUSTOMERS.BALANCE_HIDE
FROM            dbo.BANKS RIGHT OUTER JOIN
                         dbo.CUSTOMERS RIGHT OUTER JOIN
                         dbo.USERS RIGHT OUTER JOIN
                         dbo.TAKE ON dbo.USERS.USERS_ID = dbo.TAKE.A_USERS_ID ON dbo.CUSTOMERS.CUST_ID = dbo.TAKE.CUST_ID AND dbo.CUSTOMERS.CUST_ID = dbo.TAKE.CUST_ID ON 
                         dbo.BANKS.BANK_ID = dbo.TAKE.BANK_ID LEFT OUTER JOIN
                         dbo.COMMISSIONER ON dbo.TAKE.COMM_ID = dbo.COMMISSIONER.COMM_ID AND dbo.TAKE.COMM_ID = dbo.COMMISSIONER.COMM_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT AS ACC_CREDIT_1 ON dbo.TAKE.ACC_T_M_S_CREDIT_S1 = ACC_CREDIT_1.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT AS ACC_DEBIT_2 ON dbo.TAKE.ACC_T_M_S_DEBIT_S1 = ACC_DEBIT_2.AC_ID LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.TAKE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.TAKE.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.TAKE.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.TAKE.T_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                         dbo.USERS AS USERS_1 ON dbo.TAKE.USERS_ID = USERS_1.USERS_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT AS ACC_DEBIT_1 ON dbo.TAKE.ACC_T_DISCOUNT_DEBIT = ACC_DEBIT_1.AC_ID;


