                      dbo.B_R_ITEMS.CAT3, dbo.B_R_ITEMS.OFS, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.UNITS.UNIT_DISC, dbo.STORES.STORE_NAME, 
