                         dbo.COMM3_VIEW.COMM_NAME AS COMM_NAME3, dbo.COMM4_VIEW.COMM_NAME AS COMM_NAME4, dbo.REGION.REGION, dbo.PAY_DAY.DAY_PAY_NAME, dbo.CUSTOMERS.CUST_PHONE, 
                         dbo.CUSTOMERS.CUST_MOBILE, dbo.CUSTOMERS.CUST_FAX, dbo.CUSTOMERS.CUST_VENDOR, dbo.CUSTOMERS.CUST_CUSTOM, dbo.CUSTOMERS.CUST_ADRESS, dbo.CUSTOMERS.CUST_BRANCH, 
                         dbo.CUSTOMERS.CUST_MAX_DEBIT, dbo.CUSTOMERS.CUST_DISC, dbo.CUSTOMERS.CUST_INVISIBLE, dbo.CUSTOMERS.CUST_UPDATE_DATE, dbo.USERS.FULL_NAME, dbo.CUSTOMERS.COMM1_ID, 
                         dbo.CUSTOMERS.COMM2_ID, dbo.CUSTOMERS.COMM3_ID, dbo.CUSTOMERS.COMM4_ID, dbo.CUSTOMERS.PAY_DAY, dbo.CUSTOMERS.BL_CREDIT, dbo.CUSTOMERS.BL_DEBIT, dbo.CUSTOMERS.CAT8_ID, 
                         dbo.CATEOGRY8.CAT8_NAME, dbo.CUSTOMERS.CUST_EMP, dbo.CUSTOMERS.EMP_SALARY, dbo.REGION.REGION_ID, dbo.CUSTOMERS.PRICE, dbo.CUSTOMERS.PRICE_DISC, 
                         dbo.CUSTOMERS.BALANCE_HIDE, dbo.CUSTOMERS.CUST_E_MAIL, dbo.CUSTOMERS.NO_SALE_DEBIT, dbo.CUSTOMERS.ACC_ID, dbo.ACCOUNTS.AC_NAME, dbo.CUSTOMERS.BALANCE_MSG_BIT, 
                         dbo.CUSTOMERS.BALANCE_MSG, dbo.CUSTOMERS.SALE_MSG_BIT, dbo.CUSTOMERS.SALE_MSG, dbo.CUSTOMERS.TAKE_MSG_BIT, dbo.CUSTOMERS.TAKE_MSG, dbo.CUSTOMERS.GIVE_MSG_BIT, 
                         dbo.CUSTOMERS.GIVE_MSG, dbo.CUSTOMERS.MS1, dbo.CUSTOMERS.MS2, dbo.CUSTOMERS.MS3, dbo.CUSTOMERS.MS4, dbo.CUSTOMERS.MS5, dbo.CUSTOMERS.MS5_VALUE, dbo.CUSTOMERS.CAT9_ID, 
                         dbo.CATEOGRY9.CAT9_NAME, dbo.CATEOGRY8.PAY_PERENT, dbo.CUSTOMERS.BANK_ID, dbo.CUSTOMERS.TAKE_ISSUE, dbo.BANKS.BANK_NAME
FROM            dbo.CUSTOMERS LEFT OUTER JOIN
                         dbo.BANKS ON dbo.CUSTOMERS.BANK_ID = dbo.BANKS.BANK_ID LEFT OUTER JOIN
                         dbo.CATEOGRY9 ON dbo.CUSTOMERS.CAT9_ID = dbo.CATEOGRY9.CAT9_ID LEFT OUTER JOIN
                         dbo.ACCOUNTS ON dbo.CUSTOMERS.ACC_ID = dbo.ACCOUNTS.AC_ID LEFT OUTER JOIN
                         dbo.CATEOGRY8 ON dbo.CUSTOMERS.CAT8_ID = dbo.CATEOGRY8.CAT8_ID LEFT OUTER JOIN
                         dbo.COMM4_VIEW ON dbo.CUSTOMERS.COMM4_ID = dbo.COMM4_VIEW.COMM_ID LEFT OUTER JOIN
                         dbo.COMM3_VIEW ON dbo.CUSTOMERS.COMM3_ID = dbo.COMM3_VIEW.COMM_ID LEFT OUTER JOIN
                         dbo.COMM2_VIEW ON dbo.CUSTOMERS.COMM2_ID = dbo.COMM2_VIEW.COMM_ID LEFT OUTER JOIN
                         dbo.PAY_DAY ON dbo.CUSTOMERS.PAY_DAY = dbo.PAY_DAY.DAY_PAY_ID LEFT OUTER JOIN
