                         dbo.R_S_ITEMS_DELETED.UNIT_ID, dbo.R_S_ITEMS_DELETED.UNIT_QTY, dbo.R_S_ITEMS_DELETED.CATEOGRY1, dbo.R_S_ITEMS_DELETED.CATEOGRY2, dbo.R_S_ITEMS_DELETED.CATEOGRY3, 
                         dbo.R_S_ITEMS_DELETED.PRICE, dbo.R_S_ITEMS_DELETED.S_R_TIME, dbo.R_S_ITEMS_DELETED.S_R_TIME_D, dbo.R_S_ITEMS_DELETED.USERS_ID, dbo.R_S_ITEMS_DELETED.FLAG, 
                         dbo.UNITS.UNIT_DISC, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.STORES.STORE_NAME, dbo.USERS.FULL_NAME, dbo.R_S_INVOICE.S_R_DATE, dbo.R_S_INVOICE.CUST_ID, 
                         dbo.R_S_INVOICE.COMM_ID, dbo.R_S_INVOICE.TRAN_NO, dbo.R_S_INVOICE.TRAN_BARNCH
FROM            dbo.ITEMS RIGHT OUTER JOIN
                         dbo.R_S_ITEMS_DELETED LEFT OUTER JOIN
