FROM            dbo.BANKS RIGHT OUTER JOIN
                         dbo.BANKS_ACCESS ON dbo.BANKS.BANK_ID = dbo.BANKS_ACCESS.BANK_ID;


-- dbo.BANK_BALANCE_EDIT_VIEW source

CREATE OR ALTER VIEW [dbo].[BANK_BALANCE_EDIT_VIEW]
AS
SELECT        dbo.BANK_BALANCE_EDIT.B_S_ID, dbo.BANK_BALANCE_EDIT.B_S_DATE, dbo.BANK_BALANCE_EDIT.B_S_DISC, dbo.BANK_BALANCE_EDIT.BANK_ID, dbo.BANK_BALANCE_EDIT.B_S_STATUES, 
                         dbo.BANK_BALANCE_EDIT.USERs_ID, dbo.BANK_BALANCE_EDIT.B_S_UPDATE_DATE, dbo.USERS.FULL_NAME, dbo.BANKS.BANK_NAME, dbo.BANK_BALANCE_EDIT.B_S_CREDIT, 
                         dbo.BANK_BALANCE_EDIT.B_S_DEBIT, dbo.TYPE.T_NAME, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.BANK_BALANCE_EDIT.ACC_DEBIT, 
                         dbo.BANK_BALANCE_EDIT.ACC_CREDIT, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.BANK_BALANCE_EDIT.TRAN_NO, 
                         dbo.BANK_BALANCE_EDIT.TRAN_BARNCH, dbo.BANK_BALANCE_EDIT.R1
FROM            dbo.BANK_BALANCE_EDIT LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.BANK_BALANCE_EDIT.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.BANK_BALANCE_EDIT.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.BANK_BALANCE_EDIT.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.BANK_BALANCE_EDIT.B_S_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.BANK_BALANCE_EDIT.USERs_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.BANKS ON dbo.BANK_BALANCE_EDIT.BANK_ID = dbo.BANKS.BANK_ID;


-- dbo.BANK_TRANSFER_VIEW source

CREATE OR ALTER VIEW [dbo].[BANK_TRANSFER_VIEW]
AS
SELECT     dbo.BANK_TRANSFER.B_S_ID, dbo.BANK_TRANSFER.B_S_NO, dbo.BANK_TRANSFER.B_S_DATE, dbo.BANK_TRANSFER.BANK_F_ID, 
                      dbo.BANK_TRANSFER.BANK_TO_ID, dbo.BANK_TRANSFER.B_S_STATUES, dbo.BANK_TRANSFER.B_S_CHECK, dbo.BANK_TRANSFER.B_S_KIND, 
                      dbo.BANK_TRANSFER.B_S_NOTE, dbo.BANK_TRANSFER.B_S_VALUE, dbo.BANK_TRANSFER.USERS_ID, dbo.BANK_TRANSFER.B_S_UPDATE_DATE, 
                      dbo.BANKS.BANK_NAME, dbo.BANKS.BANK_ACCOUNT, dbo.BANK2.BANK_NAME AS BANK_NAME1, dbo.BANK2.BANK_ACCOUNT AS BANK_ACCOUNT2, 
                      dbo.USERS.FULL_NAME, dbo.TYPE.T_NAME, dbo.BANK_TRANSFER.B_DISC, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, 
                      dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.BANK_TRANSFER.ACC_DEBIT, dbo.BANK_TRANSFER.ACC_CREDIT, dbo.TRANS_CATEGORY.TRAN_ID, 
                      dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.BANK_TRANSFER.TRAN_NO, dbo.BANK_TRANSFER.TRAN_BARNCH
FROM         dbo.BANK_TRANSFER LEFT OUTER JOIN
                      dbo.TRANS_CATEGORY ON dbo.BANK_TRANSFER.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                      dbo.ACC_CREDIT ON dbo.BANK_TRANSFER.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                      dbo.ACC_DEBIT ON dbo.BANK_TRANSFER.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                      dbo.TYPE ON dbo.BANK_TRANSFER.B_S_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                      dbo.USERS ON dbo.BANK_TRANSFER.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                      dbo.BANK2 ON dbo.BANK_TRANSFER.BANK_TO_ID = dbo.BANK2.BANK_ID LEFT OUTER JOIN
                      dbo.BANKS ON dbo.BANK_TRANSFER.BANK_F_ID = dbo.BANKS.BANK_ID;


-- dbo.BARCODE_PRINT_LIST_VIEW source

CREATE OR ALTER VIEW [dbo].[BARCODE_PRINT_LIST_VIEW]
AS
SELECT     dbo.BARCODE_PRINT_LIST.BAR_ID, dbo.BARCODE_PRINT_LIST.X, dbo.BARCODE_PRINT_LIST.Y, dbo.BARCODE_PRINT_LIST.QTY, dbo.BARCODE.BARCODE, 
                      dbo.UNITS.UNIT_DISC, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.BARCODE.PRICE1, dbo.BARCODE_PRINT_LIST.PAGE_NO, 
                      dbo.BARCODE_PRINT_LIST.B_ID, dbo.BARCODE.UNIT_QTY
FROM         dbo.UNITS RIGHT OUTER JOIN
                      dbo.BARCODE ON dbo.UNITS.UNIT_ID = dbo.BARCODE.UNIT_ID LEFT OUTER JOIN
                      dbo.ITEMS ON dbo.BARCODE.ITEM_ID = dbo.ITEMS.ITEM_ID RIGHT OUTER JOIN
                      dbo.BARCODE_PRINT_LIST ON dbo.BARCODE.BAR_ID = dbo.BARCODE_PRINT_LIST.BAR_ID;


-- dbo.BARCODE_QTY_VIEW source

CREATE OR ALTER VIEW [dbo].[BARCODE_QTY_VIEW]
AS
SELECT     dbo.BARCODE.BAR_ID, dbo.BARCODE.UNIT_ID, dbo.UNITS.UNIT_DISC, dbo.BARCODE.UNIT_QTY, dbo.BARCODE.ITEM_ID, dbo.BARCODE.BARCODE, 
                      dbo.BARCODE.PRICE1, dbo.BARCODE.PRICE2, dbo.BARCODE.PRICE3, dbo.BARCODE.PRICE4, dbo.BARCODE.PRICE5, dbo.BARCODE.PUBLIC_PRICE, 
                      dbo.BARCODE.PRICE_LESS, dbo.BARCODE.QTY, dbo.BARCODE.PRICE_QTY, dbo.BARCODE.FREE_LEVEL, dbo.BARCODE.FREE_QTY, 
                      dbo.BARCODE.SHORT_CUT_ID, dbo.BARCODE.UPDATE_DATE, dbo.USERS.FULL_NAME, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.ITEMS.CAT1_ID, 
                      dbo.ITEMS.CAT2_ID, dbo.ITEMS.CAT3_ID, dbo.ITEMS.CAT4_ID, dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, dbo.ITEMS.CAT7_ID, dbo.ITEMS.ITEM_INVISIBLE, 
                      dbo.ITEMS.ITEM_CAT1, dbo.ITEMS.ITEM_CAT2, dbo.ITEMS.ITEM_CAT3, dbo.ITEMS.LAST_COST, dbo.ITEMS.AVER_COST, dbo.CATEGORY1.COMM_PERCENT, 
                      dbo.BARCODE.FREE_LEVEL1, dbo.BARCODE.FREE_QTY1, dbo.BARCODE.FREE_LEVEL2, dbo.BARCODE.FREE_QTY2, dbo.BARCODE.FREE_LEVEL3, 
                      dbo.BARCODE.FREE_QTY3, dbo.BARCODE.FREE_LEVEL4, dbo.BARCODE.FREE_QTY4, dbo.BARCODE.FREE_LEVEL5, dbo.BARCODE.FREE_QTY5, 
                      dbo.BARCODE.FREE_LEVEL6, dbo.BARCODE.FREE_QTY6, dbo.BARCODE.SCG_ID, dbo.SHORT_CUT_GROUPS.SCG_NAME, dbo.ITEMS.TYPE, dbo.ITEMS.MIN_LEVEL, 
                      dbo.ITEMS.MAX_LEVEL, dbo.ITEMS_SUB.QTY AS QTY1, dbo.ITEMS_IMAGES.PIC_PATH
FROM         dbo.ITEMS_SUB RIGHT OUTER JOIN
                      dbo.ITEMS_IMAGES RIGHT OUTER JOIN
                      dbo.ITEMS ON dbo.ITEMS_IMAGES.ITEM_ID = dbo.ITEMS.ITEM_ID ON dbo.ITEMS_SUB.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                      dbo.CATEGORY1 ON dbo.ITEMS.CAT1_ID = dbo.CATEGORY1.CAT1_ID RIGHT OUTER JOIN
                      dbo.SHORT_CUT_GROUPS RIGHT OUTER JOIN
                      dbo.BARCODE ON dbo.SHORT_CUT_GROUPS.SCG_ID = dbo.BARCODE.SCG_ID ON dbo.ITEMS.ITEM_ID = dbo.BARCODE.ITEM_ID LEFT OUTER JOIN
                      dbo.USERS ON dbo.BARCODE.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                      dbo.UNITS ON dbo.BARCODE.UNIT_ID = dbo.UNITS.UNIT_ID;


