                      dbo.BUY_INVOICE.B_ID, dbo.BUY_ITEMS_SERIAL_NO.ITEM_ID, dbo.STORES.STORE_NAME, dbo.BUY_INVOICE.B_STATUES, dbo.BUY_INVOICE.TRAN_NO, 
                      dbo.BUY_INVOICE.TRAN_BARNCH
