                      dbo.C_BUY_INVOICE.S_NOTE, dbo.C_BUY_INVOICE.USERS_ID, dbo.C_BUY_INVOICE.CB_UPDATE_DATE, dbo.C_BUY_INVOICE.CB_ARRIVE_DATE, 
                      dbo.CUSTOMERS.CUST_NAME, dbo.USERS.FULL_NAME, dbo.TYPE.T_NAME, dbo.C_BUY_INVOICE.S_REF_NO, dbo.C_BUY_INVOICE.TRAN_NO, 
                      dbo.C_BUY_INVOICE.TRAN_BARNCH
FROM         dbo.C_BUY_INVOICE LEFT OUTER JOIN
                      dbo.TYPE ON dbo.C_BUY_INVOICE.CB_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
