                         dbo.QYODAT_INVOICE.Q_ID AS Expr1, dbo.QYODAT_INVOICE.Q_DATE, dbo.QYODAT_INVOICE.Q_STATUES, dbo.QYODAT_INVOICE.USERS_ID, dbo.QYODAT_INVOICE.Q_UPDATE_DATE, 
