                         dbo.CATEGORY1.COMM_PERCENT, dbo.BARCODE.FREE_LEVEL1, dbo.BARCODE.FREE_QTY1, dbo.BARCODE.FREE_LEVEL2, dbo.BARCODE.FREE_QTY2, dbo.BARCODE.FREE_LEVEL3, dbo.BARCODE.FREE_QTY3, 
