-- dbo.BUY_INVOICE_VIEW source

CREATE OR ALTER VIEW [dbo].[BUY_INVOICE_VIEW]
AS
SELECT        dbo.BUY_INVOICE.B_ID, dbo.BUY_INVOICE.B_DATE, dbo.BUY_INVOICE.CUST_ID, dbo.BUY_INVOICE.COMM_ID, dbo.BUY_INVOICE.B_STATUES, dbo.BUY_INVOICE.S_NOTE, dbo.BUY_INVOICE.S_REF_NO, 
                         dbo.BUY_INVOICE.B_DISCOUNT, dbo.BUY_INVOICE.B_SPENT, dbo.BUY_INVOICE.B_UPDATE_DATE, dbo.CUSTOMERS.CUST_NO, dbo.CUSTOMERS.CUST_NAME, dbo.COMMISSIONER.COMM_NO, 
                         dbo.COMMISSIONER.COMM_NAME, dbo.USERS.FULL_NAME, dbo.TYPE.T_NAME, dbo.BUY_INVOICE.USERS_ID, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, 
                         dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.BUY_INVOICE.ACC_DEBIT, dbo.BUY_INVOICE.ACC_CREDIT, dbo.BUY_INVOICE.ACC_BUY_DIS_CREDIT, 
                         ACC_CREDIT_1.AC_NAME AS AC_NAME_DISC_CREDIT, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.LOGO, 
                         dbo.BUY_INVOICE.TRAN_NO, dbo.BUY_INVOICE.TRAN_BARNCH, dbo.CUSTOMERS.CAT8_ID
FROM            dbo.BUY_INVOICE LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.BUY_INVOICE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT AS ACC_CREDIT_1 ON dbo.BUY_INVOICE.ACC_BUY_DIS_CREDIT = ACC_CREDIT_1.AC_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.BUY_INVOICE.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.BUY_INVOICE.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.BUY_INVOICE.B_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.BUY_INVOICE.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.CUSTOMERS ON dbo.BUY_INVOICE.CUST_ID = dbo.CUSTOMERS.CUST_ID LEFT OUTER JOIN
                         dbo.COMMISSIONER ON dbo.BUY_INVOICE.COMM_ID = dbo.COMMISSIONER.COMM_ID;


