-- dbo.R_S_ITEMS_INVOICE_VIEW source

CREATE OR ALTER VIEW [dbo].[R_S_ITEMS_INVOICE_VIEW]
AS
SELECT        dbo.R_S_ITEMS.S_R_ITEM_ID, dbo.R_S_ITEMS.S_R_ID, dbo.R_S_ITEMS.ITEM_ID, dbo.R_S_ITEMS.STORE_ID, dbo.R_S_ITEMS.QTY, dbo.R_S_ITEMS.UNIT_ID, dbo.R_S_ITEMS.UNIT_QTY, 
                         dbo.R_S_ITEMS.CATEOGRY1, dbo.R_S_ITEMS.CATEOGRY2, dbo.R_S_ITEMS.CATEOGRY3, dbo.R_S_ITEMS.PRICE, dbo.R_S_ITEMS.LAST_COST, dbo.R_S_ITEMS.AVER_COST, 
                         dbo.R_S_ITEMS.AGENT_PERCENT, dbo.R_S_ITEMS.OFS, dbo.R_S_ITEMS.CAT3, dbo.R_S_INVOICE.S_R_DATE, dbo.R_S_INVOICE.S_R_STATUES, dbo.R_S_INVOICE.S_R_UPDATE_DATE, 
                         dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.UNITS.UNIT_DISC, dbo.COMMISSIONER.COMM_NO, dbo.COMMISSIONER.COMM_NAME, dbo.USERS.FULL_NAME, dbo.CUSTOMERS.CUST_NO, 
                         dbo.CUSTOMERS.CUST_NAME, dbo.R_S_INVOICE.CUST_NAME AS CUST_NAME1, dbo.R_S_INVOICE.CUST_ID, dbo.R_S_INVOICE.COMM_ID, dbo.R_S_INVOICE.BRANCH, dbo.TYPE.T_NAME, 
                         dbo.R_S_INVOICE.USERS_ID, dbo.STORES.STORE_NAME, dbo.REGION.REGION_ID, dbo.REGION.REGION, dbo.ITEMS.CAT1_ID, dbo.ITEMS.CAT2_ID, dbo.ITEMS.CAT3_ID, dbo.ITEMS.CAT4_ID, 
                         dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, dbo.ITEMS.CAT7_ID, dbo.CUSTOMERS.CAT8_ID, dbo.R_S_ITEMS.F, dbo.R_S_ITEMS.S_ID, dbo.CATEOGRY8.CAT8_NAME, dbo.R_S_ITEMS.AVER_COST_DIS, 
                         dbo.R_S_INVOICE.ACC_DEBIT, dbo.R_S_INVOICE.ACC_CREDIT, dbo.CUSTOMERS.REGION_ID AS Expr1, dbo.CUSTOMERS.CAT9_ID, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, 
                         dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.R_S_INVOICE.TRAN_NO, dbo.R_S_INVOICE.TRAN_BARNCH, dbo.R_S_INVOICE.BANK_ID
FROM            dbo.CUSTOMERS LEFT OUTER JOIN
                         dbo.CATEOGRY8 ON dbo.CUSTOMERS.CAT8_ID = dbo.CATEOGRY8.CAT8_ID LEFT OUTER JOIN
                         dbo.REGION ON dbo.CUSTOMERS.REGION_ID = dbo.REGION.REGION_ID RIGHT OUTER JOIN
                         dbo.R_S_INVOICE LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.R_S_INVOICE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.R_S_INVOICE.S_R_STATUES = dbo.TYPE.T_ID ON dbo.CUSTOMERS.CUST_ID = dbo.R_S_INVOICE.CUST_ID LEFT OUTER JOIN
                         dbo.COMMISSIONER ON dbo.R_S_INVOICE.COMM_ID = dbo.COMMISSIONER.COMM_ID RIGHT OUTER JOIN
                         dbo.STORES RIGHT OUTER JOIN
                         dbo.R_S_ITEMS ON dbo.STORES.STORE_ID = dbo.R_S_ITEMS.STORE_ID LEFT OUTER JOIN
                         dbo.ITEMS ON dbo.R_S_ITEMS.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                         dbo.UNITS ON dbo.R_S_ITEMS.UNIT_ID = dbo.UNITS.UNIT_ID ON dbo.R_S_INVOICE.S_R_ID = dbo.R_S_ITEMS.S_R_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.R_S_INVOICE.USERS_ID = dbo.USERS.USERS_ID;


-- dbo.SALARIES_VIEW source

CREATE OR ALTER VIEW [dbo].[SALARIES_VIEW]
AS
