                         dbo.USERS.FULL_NAME, dbo.BUY_INVOICE_EXPENCES.B_ID, dbo.BUY_INVOICE_EXPENCES.EXPENCES_ID, dbo.BUY_INVOICE_EXPENCES.CUST_ID, dbo.CUSTOMERS.CUST_NO, 
                         dbo.CUSTOMERS.CUST_NAME, dbo.BUY_INVOICE.B_DATE, dbo.BUY_INVOICE_EXPENCES.EXP_ID, dbo.EXPENCES_INVOICE.EXP_DATE, dbo.EXPENCES_INVOICE.USERS_ID, 
                         dbo.EXPENCES_INVOICE.EXP__STATUES, dbo.BUY_INVOICE_EXPENCES.B_EXPENCES_DISC, dbo.EXPENCES_INVOICE.ACC_DEBIT, dbo.EXPENCES_INVOICE.ACC_CREDIT, 
                         dbo.BUY_INVOICE_EXPENCES.TRAN_NO, dbo.BUY_INVOICE_EXPENCES.TRAN_BARNCH, dbo.CUSTOMERS.CAT8_ID
