                      dbo.CATEOGRY8 ON dbo.CUSTOMERS.CAT8_ID = dbo.CATEOGRY8.CAT8_ID RIGHT OUTER JOIN
                      dbo.BUY_INVOICE LEFT OUTER JOIN
                      dbo.TRANS_CATEGORY ON dbo.BUY_INVOICE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID ON 
                      dbo.CUSTOMERS.CUST_ID = dbo.BUY_INVOICE.CUST_ID LEFT OUTER JOIN
