                      dbo.B_R_INVOICE.TRAN_BARNCH
FROM         dbo.B_R_INVOICE LEFT OUTER JOIN
                      dbo.CUSTOMERS ON dbo.B_R_INVOICE.CUST_ID = dbo.CUSTOMERS.CUST_ID RIGHT OUTER JOIN
                      dbo.STORES RIGHT OUTER JOIN
                      dbo.B_R_ITEMS_SERIAL_NO LEFT OUTER JOIN
                      dbo.B_R_ITEMS ON dbo.B_R_ITEMS_SERIAL_NO.B_R_ITEM_ID = dbo.B_R_ITEMS.B_R_ITEM_ID ON 
                      dbo.STORES.STORE_ID = dbo.B_R_ITEMS.STORE_ID LEFT OUTER JOIN
                      dbo.USERS INNER JOIN
                      dbo.ITEMS ON dbo.USERS.USERS_ID = dbo.ITEMS.USERS_ID ON dbo.B_R_ITEMS_SERIAL_NO.ITEM_ID = dbo.ITEMS.ITEM_ID AND 
                      dbo.B_R_ITEMS_SERIAL_NO.USERS_ID = dbo.USERS.USERS_ID ON dbo.B_R_INVOICE.B_R_ID = dbo.B_R_ITEMS_SERIAL_NO.B_R_ID;


