-- dbo.ITEMS_SUB_BARCODE_VIEW source

CREATE OR ALTER VIEW [dbo].[ITEMS_SUB_BARCODE_VIEW]
AS
SELECT        dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.ITEMS_SUB.CATEOGRY3, dbo.CATEGORY1.CAT1_NAME, dbo.CATEGORY2.CAT2_NAME, dbo.BARCODE.PRICE1, dbo.BARCODE.PRICE2, dbo.ITEMS.CAT1_ID, 
                         dbo.ITEMS.CAT2_ID, dbo.ITEMS.CAT3_ID, dbo.ITEMS.CAT4_ID, dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, dbo.ITEMS.CAT7_ID, dbo.ITEMS.ITEM_INVISIBLE, dbo.ITEMS.ITEM_ID, dbo.UNITS.UNIT_DISC, dbo.BARCODE.UNIT_ID, 
                         dbo.ITEMS.TYPE, dbo.BARCODE.UNIT_QTY, dbo.ITEMS.NO_COST, dbo.CATEOGRY3.CAT3_NAME, dbo.CATEOGRY4.CAT4_NAME, dbo.CATEOGRY5.CAT5_NAME, dbo.ITEMS_SUB.STORE_ID, dbo.ITEMS_SUB.QTY, 
                         dbo.BARCODE.BARCODE
FROM            dbo.BARCODE INNER JOIN
                         dbo.ITEMS ON dbo.BARCODE.ITEM_ID = dbo.ITEMS.ITEM_ID INNER JOIN
                         dbo.CATEGORY1 ON dbo.ITEMS.CAT1_ID = dbo.CATEGORY1.CAT1_ID INNER JOIN
                         dbo.CATEGORY2 ON dbo.ITEMS.CAT2_ID = dbo.CATEGORY2.CAT2_ID INNER JOIN
                         dbo.UNITS ON dbo.BARCODE.UNIT_ID = dbo.UNITS.UNIT_ID LEFT OUTER JOIN
                         dbo.CATEOGRY5 ON dbo.ITEMS.CAT5_ID = dbo.CATEOGRY5.CAT5_ID LEFT OUTER JOIN
                         dbo.CATEOGRY3 ON dbo.ITEMS.CAT3_ID = dbo.CATEOGRY3.CAT3_ID LEFT OUTER JOIN
                         dbo.CATEOGRY4 ON dbo.ITEMS.CAT4_ID = dbo.CATEOGRY4.CAT4_ID RIGHT OUTER JOIN
                         dbo.ITEMS_SUB ON dbo.ITEMS.ITEM_ID = dbo.ITEMS_SUB.ITEM_ID;


-- dbo.ITEMS_SUB_ITEMS_VIEW source

CREATE OR ALTER VIEW [dbo].[ITEMS_SUB_ITEMS_VIEW]
AS
SELECT        dbo.ITEMS_SUB_ITEMS.BAR_ID_MAIN, dbo.ITEMS_SUB_ITEMS.BAR_ID_BRANCH, dbo.ITEMS_SUB_ITEMS.QTY, dbo.BARCODE_VIEW.UNIT_ID AS UNIT_ID_MAIN, 
                         dbo.BARCODE_VIEW.UNIT_DISC AS UNIT_DISC_MAIN, dbo.BARCODE_VIEW.UNIT_QTY AS UNIT_QTY_MAIN, dbo.BARCODE_VIEW.ITEM_ID AS ITEM_ID_MAIN, 
                         dbo.BARCODE_VIEW.ITEM_MODEL AS ITEM_MODEL_MAIN, dbo.BARCODE_VIEW.ITEM_NAME AS ITEM_NAME_MAIN, BARCODE_VIEW_1.UNIT_ID AS UNIT_ID_BRANCH, 
                         BARCODE_VIEW_1.UNIT_DISC AS UNIT_DISC_BRANCH, BARCODE_VIEW_1.UNIT_QTY AS UNIT_QTY_BRANCH, BARCODE_VIEW_1.ITEM_ID AS ITEM_ID_BRANCH, 
                         BARCODE_VIEW_1.PRICE1 AS PRICE1_BRANCH, BARCODE_VIEW_1.ITEM_MODEL AS ITEM_MODEL_BRANCH, BARCODE_VIEW_1.ITEM_NAME AS ITEM_NAME_BRANCH, dbo.ITEMS_SUB_ITEMS.PRICE
FROM            dbo.ITEMS_SUB_ITEMS LEFT OUTER JOIN
                         dbo.BARCODE_VIEW AS BARCODE_VIEW_1 ON dbo.ITEMS_SUB_ITEMS.BAR_ID_BRANCH = BARCODE_VIEW_1.BAR_ID LEFT OUTER JOIN
                         dbo.BARCODE_VIEW ON dbo.ITEMS_SUB_ITEMS.BAR_ID_MAIN = dbo.BARCODE_VIEW.BAR_ID;


-- dbo.ITEMS_VIEW source

CREATE OR ALTER VIEW [dbo].[ITEMS_VIEW]
AS
SELECT        dbo.ITEMS.ITEM_ID, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.ITEMS.CAT1_ID, dbo.CATEGORY1.CAT1_NAME, dbo.ITEMS.CAT2_ID, dbo.CATEGORY2.CAT2_NAME, dbo.ITEMS.CAT3_ID, 
                         dbo.CATEOGRY3.CAT3_NAME, dbo.ITEMS.CAT4_ID, dbo.CATEOGRY4.CAT4_NAME, dbo.ITEMS.CAT5_ID, dbo.CATEOGRY5.CAT5_NAME, dbo.ITEMS.CAT6_ID, dbo.CATEOGRY6.CAT6_NAME, dbo.ITEMS.CAT7_ID, 
                         dbo.CATEOGRY7.CAT7_NAME, dbo.ITEMS.MAX_LEVEL, dbo.ITEMS.MIN_LEVEL, dbo.ITEMS.LAST_COST, dbo.ITEMS.AVER_COST, dbo.ITEMS.ITEM_INVISIBLE, dbo.ITEMS.TYPE, dbo.ITEMS.ITEM_CAT1, dbo.ITEMS.ITEM_CAT2, 
                         dbo.ITEMS.ITEM_CAT3, dbo.ITEMS.ITEM_UPDATE_DATE, dbo.USERS.FULL_NAME, dbo.CATEGORY1.COMM_PERCENT, dbo.ITEMS.PLACE, dbo.ITEMS.SERIAL, dbo.ITEMS_IMAGES.PIC_PATH, dbo.ITEMS.NO_COST, 
                         dbo.ITEMS.AVER_COST_AFTER, dbo.ITEMS.PRICE_QTY
FROM            dbo.CATEGORY1 RIGHT OUTER JOIN
                         dbo.CATEOGRY3 RIGHT OUTER JOIN
                         dbo.CATEOGRY7 RIGHT OUTER JOIN
                         dbo.ITEMS LEFT OUTER JOIN
                         dbo.ITEMS_IMAGES ON dbo.ITEMS.ITEM_ID = dbo.ITEMS_IMAGES.ITEM_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.ITEMS.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.CATEGORY2 ON dbo.ITEMS.CAT2_ID = dbo.CATEGORY2.CAT2_ID LEFT OUTER JOIN
                         dbo.CATEOGRY4 ON dbo.ITEMS.CAT4_ID = dbo.CATEOGRY4.CAT4_ID ON dbo.CATEOGRY7.CAT7_ID = dbo.ITEMS.CAT7_ID ON dbo.CATEOGRY3.CAT3_ID = dbo.ITEMS.CAT3_ID ON 
                         dbo.CATEGORY1.CAT1_ID = dbo.ITEMS.CAT1_ID LEFT OUTER JOIN
                         dbo.CATEOGRY6 ON dbo.ITEMS.CAT6_ID = dbo.CATEOGRY6.CAT6_ID LEFT OUTER JOIN
                         dbo.CATEOGRY5 ON dbo.ITEMS.CAT5_ID = dbo.CATEOGRY5.CAT5_ID;


-- dbo.ITEM_SUB_VIEW source

CREATE OR ALTER VIEW [dbo].[ITEM_SUB_VIEW]
AS
SELECT     dbo.ITEMS_SUB.ITEM_SUB_ID, dbo.ITEMS_SUB.ITEM_ID, dbo.ITEMS_SUB.STORE_ID, dbo.ITEMS_SUB.QTY, dbo.ITEMS_SUB.CATEOGRY1, 
                      dbo.ITEMS_SUB.CATEOGRY2, dbo.ITEMS_SUB.CATEOGRY3, dbo.ITEMS_SUB.OFS, dbo.STORES.STORE_NAME, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, 
                      dbo.ITEMS_SUB.CAT3, dbo.ITEMS.CAT1_ID, dbo.ITEMS.CAT2_ID, dbo.ITEMS.CAT3_ID, dbo.ITEMS.CAT4_ID, dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, 
                      dbo.ITEMS.CAT7_ID, dbo.ITEMS.ITEM_INVISIBLE, dbo.ITEMS.LAST_COST, dbo.ITEMS.AVER_COST, dbo.ITEMS.TYPE, dbo.ITEMS.PLACE, dbo.ITEMS.MIN_LEVEL, 
                      dbo.ITEMS.MAX_LEVEL, dbo.ITEMS.AVER_COST_DIS, dbo.CATEGORY1.CAT1_NAME, dbo.CATEGORY2.CAT2_NAME
FROM         dbo.ITEMS LEFT OUTER JOIN
                      dbo.CATEGORY2 ON dbo.ITEMS.CAT2_ID = dbo.CATEGORY2.CAT2_ID LEFT OUTER JOIN
                      dbo.CATEGORY1 ON dbo.ITEMS.CAT1_ID = dbo.CATEGORY1.CAT1_ID RIGHT OUTER JOIN
