                         dbo.Invoice_Items.Batch, dbo.Invoice_Items.Expiry, dbo.Invoice_Items.StoreID, dbo.Invoice_Items.ItemCat1, dbo.Invoice_Items.ItemCat2, dbo.Invoice_Items.ItemCat3, dbo.Invoice_Items.ID, dbo.STORES.STORE_NAME
