-- dbo.JARED_ITEMS_DELETED_VIEW source

CREATE OR ALTER VIEW [dbo].[JARED_ITEMS_DELETED_VIEW]
AS
SELECT        dbo.JARED_ITEMS_DELETED.J_ITEM_ID, dbo.JARED_ITEMS_DELETED.J_ID, dbo.JARED_ITEMS_DELETED.ITEM_ID, dbo.JARED_ITEMS_DELETED.STORE_ID, dbo.JARED_ITEMS_DELETED.QTY, 
                         dbo.JARED_ITEMS_DELETED.UNIT_ID, dbo.JARED_ITEMS_DELETED.UNIT_QTY, dbo.JARED_ITEMS_DELETED.CATEOGRY1, dbo.JARED_ITEMS_DELETED.CATEOGRY2, 
                         dbo.JARED_ITEMS_DELETED.CATEOGRY3, dbo.JARED_ITEMS_DELETED.PRICE, dbo.JARED_ITEMS_DELETED.J_TIME, dbo.JARED_ITEMS_DELETED.J_TIME_D, dbo.JARED_ITEMS_DELETED.USERS_ID, 
                         dbo.JARED_ITEMS_DELETED.FLAG, dbo.USERS.FULL_NAME, dbo.UNITS.UNIT_DISC, dbo.STORES.STORE_NAME, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.JARED_INVOICE.J_DATE, 
                         dbo.JARED_INVOICE.TRAN_NO, dbo.JARED_INVOICE.TRAN_BARNCH
FROM            dbo.STORES RIGHT OUTER JOIN
                         dbo.ITEMS RIGHT OUTER JOIN
                         dbo.JARED_ITEMS_DELETED LEFT OUTER JOIN
                         dbo.JARED_INVOICE ON dbo.JARED_ITEMS_DELETED.J_ID = dbo.JARED_INVOICE.J_ID ON dbo.ITEMS.ITEM_ID = dbo.JARED_ITEMS_DELETED.ITEM_ID ON 
                         dbo.STORES.STORE_ID = dbo.JARED_ITEMS_DELETED.STORE_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.JARED_ITEMS_DELETED.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.UNITS ON dbo.JARED_ITEMS_DELETED.UNIT_ID = dbo.UNITS.UNIT_ID;


-- dbo.JARED_ITEMS_SERIAL_NO_VIEW source

CREATE OR ALTER VIEW [dbo].[JARED_ITEMS_SERIAL_NO_VIEW]
AS
SELECT     dbo.JARED_ITEMS_SERIAL_NO.J_S_ID, dbo.JARED_ITEMS_SERIAL_NO.ITEMS_JARED_ID, dbo.JARED_ITEMS_SERIAL_NO.SERIAL_NO, 
                      dbo.JARED_ITEMS_SERIAL_NO.J_S_UPDATE_DATE, dbo.JARED_ITEMS_SERIAL_NO.USERS_ID, dbo.USERS.FULL_NAME, dbo.ITEMS.ITEM_MODEL, 
                      dbo.ITEMS.ITEM_NAME, dbo.JARED_INVOICE.J_DATE, dbo.JARED_INVOICE.J_REF_DISC, dbo.JARED_ITEMS_SERIAL_NO.J_ID, 
                      dbo.JARED_ITEMS_SERIAL_NO.ITEM_ID, dbo.STORE_VIEW1.STORE_NAME, dbo.JARED_INVOICE.J_STATUES, dbo.JARED_INVOICE.TRAN_NO, 
                      dbo.JARED_INVOICE.TRAN_BARNCH
FROM         dbo.ITEMS RIGHT OUTER JOIN
                      dbo.JARED_ITEMS_SERIAL_NO LEFT OUTER JOIN
                      dbo.STORE_VIEW1 RIGHT OUTER JOIN
                      dbo.JARED_ITEMS ON dbo.STORE_VIEW1.STORE_ID = dbo.JARED_ITEMS.STORE_ID ON 
