                      dbo.M_SALE_ITEMS.CATEOGRY2, dbo.M_SALE_ITEMS.CATEOGRY3, dbo.M_SALE_ITEMS.CAT3, dbo.M_SALE_ITEMS.OFS, dbo.M_SALE_ITEMS.PRICE,
                       dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.UNITS.UNIT_DISC, dbo.STORES.STORE_NAME, dbo.M_SALE_INVOICE.SHIPMENT, 
                      dbo.M_SALE_INVOICE.MS_TAX2, dbo.M_SALE_INVOICE.MS_TAX1, dbo.M_SALE_INVOICE.MS_DISCOUNT, dbo.M_SALE_INVOICE.MS_STATUES, 
                      dbo.M_SALE_INVOICE.LAST_DATE, dbo.M_SALE_ITEMS.PUBLIC_PRICE, dbo.M_SALE_ITEMS.AGENT_PERCENT, dbo.M_SALE_ITEMS.COLLECT_ID, 
                      dbo.M_SALE_ITEMS.S_ITEM_INVISIBLE
FROM         dbo.M_SALE_ITEMS LEFT OUTER JOIN
                      dbo.M_SALE_INVOICE ON dbo.M_SALE_ITEMS.MS_ID = dbo.M_SALE_INVOICE.MS_ID LEFT OUTER JOIN
                      dbo.STORES ON dbo.M_SALE_ITEMS.STORE_ID = dbo.STORES.STORE_ID LEFT OUTER JOIN
                      dbo.ITEMS ON dbo.M_SALE_ITEMS.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                      dbo.UNITS ON dbo.M_SALE_ITEMS.UNIT_ID = dbo.UNITS.UNIT_ID;


