                         dbo.SALARIES.BORROW_DISCOUNT, dbo.SALARIES.PENALTY, dbo.SALARIES.PENALTY_REASON, dbo.SALARIES.NOTES, dbo.SALARIES.CUST_ID, dbo.CUSTOMERS.CUST_NAME, dbo.SALARIES.S_STATUES, 
                         dbo.SALARIES.S_DATE, dbo.SALARIES.USERS_ID, dbo.SALARIES.S_UPDATE_DATE, dbo.USERS.FULL_NAME, dbo.SALARIES.TOTAL_HOURS, dbo.SALARIES.HOUR_VALUE, dbo.SALARIES.ACC_DEBIT, 
                         dbo.SALARIES.ACC_CREDIT, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.CUSTOMERS.CAT8_ID
FROM            dbo.SALARIES LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.SALARIES.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.SALARIES.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.SALARIES.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.CUSTOMERS ON dbo.SALARIES.CUST_ID = dbo.CUSTOMERS.CUST_ID;


-- dbo.SALE_INVOICE_PAY_CHECK_VIEW source

