-- dbo.SALE_INVOICE_VIEW source

CREATE OR ALTER VIEW [dbo].[SALE_INVOICE_VIEW]
AS
SELECT        dbo.SALE_INVOICE.S_ID, dbo.SALE_INVOICE.S_DATE, dbo.SALE_INVOICE.CUST_ID, dbo.SALE_INVOICE.COMM_ID, dbo.SALE_INVOICE.S_STATUES, dbo.SALE_INVOICE.USERS_ID, dbo.SALE_INVOICE.S_NOTE, 
                         dbo.SALE_INVOICE.S_DISCOUNT, dbo.SALE_INVOICE.S_TAX1, dbo.SALE_INVOICE.S_TAX2, dbo.SALE_INVOICE.S_SHIPMENT, dbo.SALE_INVOICE.S_UPDATE_DATE, dbo.CUSTOMERS.CUST_NO, 
                         dbo.USERS.FULL_NAME, dbo.COMMISSIONER.COMM_NO, dbo.COMMISSIONER.COMM_NAME, dbo.CUSTOMERS.CUST_NAME, dbo.SALE_INVOICE.CUST_NAME AS CUST_NAME_CASH, 
                         dbo.SALE_INVOICE.BRANCH, dbo.COMMISSIONER.COMM_PHONE, dbo.CUSTOMERS.CUST_ADRESS, dbo.TYPE.T_NAME, dbo.CUSTOMERS.CUST_MAX_DEBIT, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, 
                         dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, dbo.SALE_INVOICE.ACC_DEBIT, dbo.SALE_INVOICE.ACC_CREDIT, dbo.SALE_INVOICE.ACC_DIS_DEBIT, dbo.SALE_INVOICE.ACC_TAX_CREDIT, 
                         ACC_DEBIT_1.AC_ID, ACC_DEBIT_1.AC_NAME AS AC_NAME_DISC_DEBIT, ACC_CREDIT_1.AC_NAME AS AC_NAME_TAX_CREDIT, dbo.SALE_INVOICE.KITCHEN, dbo.BANKS.BANK_NAME, 
                         dbo.SALE_INVOICE.BANK_ID, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.LOGO, dbo.SALE_INVOICE.TRAN_NO, 
                         dbo.SALE_INVOICE.TRAN_BARNCH, dbo.CUSTOMERS.CAT8_ID, dbo.SALE_INVOICE.WAIT, dbo.CUSTOMERS.CUST_PHONE, dbo.CUSTOMERS.CUST_MOBILE
FROM            dbo.CUSTOMERS RIGHT OUTER JOIN
                         dbo.SALE_INVOICE LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.SALE_INVOICE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.BANKS ON dbo.SALE_INVOICE.BANK_ID = dbo.BANKS.BANK_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT AS ACC_DEBIT_1 ON dbo.SALE_INVOICE.ACC_DIS_DEBIT = ACC_DEBIT_1.AC_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT AS ACC_CREDIT_1 ON dbo.SALE_INVOICE.ACC_TAX_CREDIT = ACC_CREDIT_1.AC_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.SALE_INVOICE.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.SALE_INVOICE.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.SALE_INVOICE.S_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.SALE_INVOICE.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.COMMISSIONER ON dbo.SALE_INVOICE.COMM_ID = dbo.COMMISSIONER.COMM_ID ON dbo.CUSTOMERS.CUST_ID = dbo.SALE_INVOICE.CUST_ID;


