                      dbo.S_R_ITEMS_SERIAL_NO.S_R_S_UPDATE_DATE, dbo.S_R_ITEMS_SERIAL_NO.USERS_ID, dbo.USERS.FULL_NAME, dbo.ITEMS.ITEM_MODEL, 
                      dbo.ITEMS.ITEM_NAME, dbo.R_S_INVOICE.S_R_DATE, dbo.CUSTOMERS.CUST_ID, dbo.CUSTOMERS.CUST_NO, dbo.CUSTOMERS.CUST_NAME, 
                      dbo.R_S_INVOICE.S_R_ID, dbo.STORES.STORE_NAME, dbo.ITEMS.ITEM_ID, dbo.R_S_INVOICE.S_R_STATUES, dbo.R_S_INVOICE.TRAN_NO, 
                      dbo.R_S_INVOICE.TRAN_BARNCH
FROM         dbo.R_S_INVOICE LEFT OUTER JOIN
