AS
SELECT     dbo.TRANSFER_INVOICE.TR_ID, dbo.TRANSFER_INVOICE.TR_DATE, dbo.TRANSFER_INVOICE.TR_DISC, dbo.TRANSFER_INVOICE.TR_STATUES, 
                      dbo.TRANSFER_INVOICE.TR_NOTE, dbo.TRANSFER_INVOICE.USERS_ID, dbo.TRANSFER_INVOICE.TR_UPDATE_DATE, dbo.USERS.FULL_NAME, dbo.TYPE.T_NAME, 
                      dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.LOGO, 
                      dbo.TRANSFER_INVOICE.TRAN_NO, dbo.TRANSFER_INVOICE.TRAN_BARNCH
FROM         dbo.TRANSFER_INVOICE LEFT OUTER JOIN
                      dbo.TRANS_CATEGORY ON dbo.TRANSFER_INVOICE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                      dbo.TYPE ON dbo.TRANSFER_INVOICE.TR_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
