-- dbo.ACCOUNTS_TO_TYPE_VIEW source

CREATE OR ALTER VIEW [dbo].[ACCOUNTS_TO_TYPE_VIEW]
AS
SELECT     dbo.ACCOUNTS_TO_TYPES.AC_TYPE_ID, dbo.ACCOUNTS_TO_TYPES.AC_ID, dbo.ACCOUNTS_TO_TYPES.AC_TYPE, dbo.ACCOUNT_TYPE.AC_NAME_TYPE, 
                      dbo.ACC_CREDIT.AC_NAME
FROM         dbo.ACCOUNTS_TO_TYPES LEFT OUTER JOIN
                      dbo.ACC_CREDIT ON dbo.ACCOUNTS_TO_TYPES.AC_ID = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                      dbo.ACCOUNT_TYPE ON dbo.ACCOUNTS_TO_TYPES.AC_TYPE = dbo.ACCOUNT_TYPE.AC_TYPE;


-- dbo.ACCOUNT_PARENT_VIEW source

CREATE OR ALTER VIEW [dbo].[ACCOUNT_PARENT_VIEW]
AS
SELECT     AC_ID, AC_LEVEL, AC_P_ID, AC_NO, AC_NAME, PARENT, AC_DISC, AC_DEBIT_CREDIT_TYPE, AC_TYPE, AC_G_A, DEPRECIATION, DEP_FLAG, AC_NOTES, 
                      MAX_BALANCE, UPDATE_DATE, USERS_ID
FROM         dbo.ACCOUNTS;


-- dbo.ACCOUNT_VIEW source

CREATE OR ALTER VIEW [dbo].[ACCOUNT_VIEW]
AS
SELECT        dbo.ACCOUNTS.AC_ID, dbo.ACCOUNTS.PARENT, dbo.ACCOUNTS.AC_LEVEL, dbo.ACCOUNTS.AC_P_ID, dbo.ACCOUNTS.AC_NO, dbo.ACCOUNTS.AC_NAME, dbo.ACCOUNTS.AC_DISC, dbo.ACCOUNTS.AC_DEBIT_CREDIT_TYPE, 
                         dbo.ACCOUNTS.AC_TYPE, dbo.ACCOUNTS.AC_G_A, dbo.ACCOUNTS.DEPRECIATION, dbo.ACCOUNTS.DEP_FLAG, dbo.ACCOUNTS.AC_NOTES, dbo.ACCOUNTS.MAX_BALANCE, dbo.ACCOUNTS.UPDATE_DATE, 
                         dbo.ACCOUNTS.USERS_ID, dbo.USERS.FULL_NAME, dbo.ACCOUNT_TYPE.AC_NAME_TYPE, dbo.ACCOUNT_PARENT_VIEW.AC_NO AS AC_NO_P, dbo.ACCOUNT_PARENT_VIEW.AC_NAME AS AC_NAME_P, 
                         dbo.ACCOUNTS.ACCOUNT_COLLECT
FROM            dbo.ACCOUNTS LEFT OUTER JOIN
                         dbo.ACCOUNT_PARENT_VIEW ON dbo.ACCOUNTS.AC_P_ID = dbo.ACCOUNT_PARENT_VIEW.AC_ID LEFT OUTER JOIN
                         dbo.ACCOUNT_TYPE ON dbo.ACCOUNTS.AC_TYPE = dbo.ACCOUNT_TYPE.AC_TYPE LEFT OUTER JOIN
                         dbo.USERS ON dbo.ACCOUNTS.USERS_ID = dbo.USERS.USERS_ID;


-- dbo.ACC_CREDIT source

CREATE OR ALTER VIEW [dbo].[ACC_CREDIT]
AS
SELECT     AC_ID, AC_NAME
FROM         dbo.ACCOUNTS;


-- dbo.ACC_DEBIT source

CREATE OR ALTER VIEW [dbo].[ACC_DEBIT]
AS
SELECT     AC_ID, AC_NAME
FROM         dbo.ACCOUNTS;


-- dbo.BALANCE_C_VIEW source

CREATE OR ALTER VIEW [dbo].[BALANCE_C_VIEW]
AS
SELECT     dbo.ACCOUNT_VIEW.AC_NAME, dbo.ACCOUNT_VIEW.PARENT, dbo.BALANCE_C.ACC_ID, dbo.BALANCE_C.ACC_DEBIT, dbo.BALANCE_C.ACC_CREDIT, 
                      dbo.BALANCE_C.BALANCE, dbo.BALANCE_C.ACC_DEBIT_T, dbo.BALANCE_C.ACC_CREDIT_T, dbo.BALANCE_C.BALANCE_T, dbo.ACCOUNT_VIEW.AC_NO
FROM         dbo.BALANCE_C LEFT OUTER JOIN
                      dbo.ACCOUNT_VIEW ON dbo.BALANCE_C.ACC_ID = dbo.ACCOUNT_VIEW.AC_ID;


-- dbo.BALANCE_EDIT_VIEW source

CREATE OR ALTER VIEW [dbo].[BALANCE_EDIT_VIEW]
AS
SELECT        dbo.BALANCE_EDIT.BL_ID, dbo.BALANCE_EDIT.BL_DATE, dbo.BALANCE_EDIT.BL_DISC, dbo.BALANCE_EDIT.CUST_ID, dbo.BALANCE_EDIT.COMM_ID, dbo.BALANCE_EDIT.BL_CREDIT, 
                         dbo.BALANCE_EDIT.BL_DEBIT, dbo.BALANCE_EDIT.USERS_ID, dbo.BALANCE_EDIT.BL_UPDATE_DATE, dbo.CUSTOMERS.CUST_NO, dbo.CUSTOMERS.CUST_NAME, dbo.COMMISSIONER.COMM_NO, 
                         dbo.COMMISSIONER.COMM_NAME, dbo.USERS.FULL_NAME, dbo.BALANCE_EDIT.BL_STATUES, dbo.TYPE.T_NAME, TYPE_1.T_NAME AS Expr1, dbo.BALANCE_EDIT.COMM_PERCENT, 
                         dbo.BALANCE_EDIT.RATE, dbo.BALANCE_EDIT.CURRENCY_ID, dbo.CURRENCY.CURRENCY_DISC, dbo.ACC_DEBIT.AC_NAME AS AC_NAME_DEBIT, dbo.ACC_CREDIT.AC_NAME AS AC_NAME_CREDIT, 
                         dbo.BALANCE_EDIT.ACC_DEBIT, dbo.BALANCE_EDIT.ACC_CREDIT, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, 
                         dbo.BALANCE_EDIT.TRAN_NO, dbo.BALANCE_EDIT.TRAN_BARNCH, dbo.CUSTOMERS.CAT8_ID, dbo.BALANCE_EDIT.R1, dbo.CUSTOMERS.BALANCE_HIDE
FROM            dbo.BALANCE_EDIT LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.BALANCE_EDIT.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.BALANCE_EDIT.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.BALANCE_EDIT.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.CURRENCY ON dbo.BALANCE_EDIT.CURRENCY_ID = dbo.CURRENCY.CURRENCY_ID LEFT OUTER JOIN
                         dbo.TYPE AS TYPE_1 ON dbo.BALANCE_EDIT.BL_STATUES = TYPE_1.T_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.BALANCE_EDIT.BL_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                         dbo.COMMISSIONER ON dbo.BALANCE_EDIT.COMM_ID = dbo.COMMISSIONER.COMM_ID LEFT OUTER JOIN
                         dbo.CUSTOMERS ON dbo.BALANCE_EDIT.CUST_ID = dbo.CUSTOMERS.CUST_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.BALANCE_EDIT.USERS_ID = dbo.USERS.USERS_ID;


-- dbo.BALANCE_T_VIEW source

CREATE OR ALTER VIEW [dbo].[BALANCE_T_VIEW]
AS
SELECT        dbo.ACCOUNT_VIEW.AC_NAME, dbo.ACCOUNT_VIEW.PARENT, dbo.BALANCE_T.ACC_ID, dbo.BALANCE_T.ACC_DEBIT, dbo.BALANCE_T.ACC_CREDIT, dbo.BALANCE_T.BALANCE, dbo.BALANCE_T.ACC_DEBIT_T, 
                         dbo.BALANCE_T.ACC_CREDIT_T, dbo.BALANCE_T.BALANCE_T, dbo.ACCOUNT_VIEW.AC_NO, dbo.ACCOUNT_VIEW.AC_P_ID
FROM            dbo.BALANCE_T LEFT OUTER JOIN
                         dbo.ACCOUNT_VIEW ON dbo.BALANCE_T.ACC_ID = dbo.ACCOUNT_VIEW.AC_ID;


