                      dbo.BUY_ITEMS.UNIT_QTY, dbo.BUY_ITEMS.CATEOGRY1, dbo.BUY_ITEMS.CATEOGRY2, dbo.BUY_ITEMS.CATEOGRY3, dbo.BUY_ITEMS.PRICE, 
                      dbo.BUY_ITEMS.RATE, dbo.BUY_ITEMS.CURRENCY_ID, dbo.BUY_ITEMS.OFS, dbo.BUY_ITEMS.CAT3, dbo.BUY_INVOICE.B_DATE, dbo.BUY_INVOICE.CUST_ID, 
                      dbo.BUY_INVOICE.COMM_ID, dbo.BUY_INVOICE.B_STATUES, dbo.BUY_INVOICE.S_REF_NO, dbo.BUY_INVOICE.B_DISCOUNT, dbo.BUY_INVOICE.B_SPENT, 
                      dbo.USERS.FULL_NAME, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.UNITS.UNIT_DISC, dbo.CURRENCY.CURRENCY_DISC, dbo.CUSTOMERS.CUST_NO, 
                      dbo.CUSTOMERS.CUST_NAME, dbo.STORES.STORE_NAME, dbo.BUY_INVOICE.USERS_ID, dbo.ITEMS.CAT1_ID, dbo.ITEMS.CAT2_ID, dbo.ITEMS.CAT3_ID, 
                      dbo.ITEMS.CAT4_ID, dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, dbo.ITEMS.CAT7_ID, dbo.BUY_ITEMS.F, dbo.BUY_ITEMS.BARCODE, dbo.CUSTOMERS.CAT9_ID, 
                      dbo.CATEOGRY8.CAT8_ID, dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, 
                      dbo.BUY_INVOICE.TRAN_NO, dbo.BUY_INVOICE.TRAN_BARNCH
