-- dbo.ITEMS_BARCODE_QTY_VIEW source

CREATE OR ALTER VIEW [dbo].[ITEMS_BARCODE_QTY_VIEW]
AS
SELECT        dbo.ITEMS.ITEM_ID, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.ITEMS.AVER_COST, dbo.BARCODE.UNIT_QTY, dbo.ITEMS.ITEM_CAT1, dbo.ITEMS.ITEM_CAT2, dbo.ITEMS.ITEM_CAT3, 
                         dbo.ITEMS.MIN_LEVEL, dbo.BARCODE.PRICE1, dbo.UNITS.UNIT_DISC, dbo.ITEMS_SUB.QTY, dbo.ITEMS.TYPE, dbo.ITEMS.LAST_COST, dbo.ITEMS.ITEM_INVISIBLE, dbo.CATEOGRY3.CAT3_ID, 
                         dbo.CATEOGRY4.CAT4_ID, dbo.CATEOGRY6.CAT6_ID, dbo.CATEOGRY5.CAT5_ID, dbo.CATEOGRY7.CAT7_ID, dbo.CATEGORY1.CAT1_ID, dbo.CATEGORY2.CAT2_ID, dbo.CATEGORY1.COMM_PERCENT, 
                         dbo.ITEMS_SUB.STORE_ID, dbo.ITEMS_IMAGES.PIC_PATH, dbo.BARCODE.PRICE2, dbo.BARCODE.PRICE3, dbo.BARCODE.PRICE4, dbo.BARCODE.PRICE5, dbo.BARCODE.PUBLIC_PRICE, 
                         dbo.BARCODE.PRICE_LESS, dbo.BARCODE.PRICE_QTY, dbo.BARCODE.FREE_LEVEL, dbo.BARCODE.FREE_QTY, dbo.BARCODE.QTY AS QTY1, dbo.BARCODE.BARCODE, dbo.ITEMS.NO_COST, 
                         dbo.BARCODE.BAR_ID, dbo.STORES.STORE_NAME, dbo.ITEMS.AVER_COST_AFTER
FROM            dbo.STORES RIGHT OUTER JOIN
                         dbo.ITEMS_SUB ON dbo.STORES.STORE_ID = dbo.ITEMS_SUB.STORE_ID RIGHT OUTER JOIN
                         dbo.ITEMS_IMAGES RIGHT OUTER JOIN
                         dbo.ITEMS ON dbo.ITEMS_IMAGES.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                         dbo.CATEOGRY4 ON dbo.ITEMS.CAT4_ID = dbo.CATEOGRY4.CAT4_ID LEFT OUTER JOIN
                         dbo.CATEGORY2 ON dbo.ITEMS.CAT2_ID = dbo.CATEGORY2.CAT2_ID LEFT OUTER JOIN
                         dbo.CATEOGRY7 ON dbo.ITEMS.CAT7_ID = dbo.CATEOGRY7.CAT7_ID LEFT OUTER JOIN
                         dbo.CATEGORY1 ON dbo.ITEMS.CAT1_ID = dbo.CATEGORY1.CAT1_ID LEFT OUTER JOIN
                         dbo.CATEOGRY6 ON dbo.ITEMS.CAT6_ID = dbo.CATEOGRY6.CAT6_ID LEFT OUTER JOIN
                         dbo.CATEOGRY3 ON dbo.ITEMS.CAT3_ID = dbo.CATEOGRY3.CAT3_ID LEFT OUTER JOIN
                         dbo.CATEOGRY5 ON dbo.ITEMS.CAT5_ID = dbo.CATEOGRY5.CAT5_ID RIGHT OUTER JOIN
                         dbo.UNITS RIGHT OUTER JOIN
                         dbo.BARCODE ON dbo.UNITS.UNIT_ID = dbo.BARCODE.UNIT_ID ON dbo.ITEMS.ITEM_ID = dbo.BARCODE.ITEM_ID ON dbo.ITEMS_SUB.ITEM_ID = dbo.ITEMS.ITEM_ID;


-- dbo.ITEMS_BARCODE_QTY_VIEW11 source

CREATE OR ALTER VIEW [dbo].[ITEMS_BARCODE_QTY_VIEW11]
AS
SELECT        dbo.ITEMS.ITEM_ID, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.ITEMS.AVER_COST, dbo.ITEMS.ITEM_CAT1, dbo.ITEMS.ITEM_CAT2, dbo.ITEMS.ITEM_CAT3, dbo.ITEMS.MIN_LEVEL, 
                         dbo.ITEMS_SUB.QTY, dbo.ITEMS.TYPE, dbo.ITEMS.LAST_COST, dbo.ITEMS.ITEM_INVISIBLE, dbo.CATEOGRY3.CAT3_ID, dbo.CATEOGRY4.CAT4_ID, dbo.CATEOGRY6.CAT6_ID, dbo.CATEOGRY5.CAT5_ID, 
                         dbo.CATEOGRY7.CAT7_ID, dbo.CATEGORY1.CAT1_ID, dbo.CATEGORY2.CAT2_ID, dbo.CATEGORY1.COMM_PERCENT, dbo.ITEMS_SUB.STORE_ID, dbo.ITEMS.NO_COST, dbo.ITEMS.CAT1_ID AS Expr1, 
                         dbo.ITEMS.CAT2_ID AS Expr2, dbo.ITEMS.CAT3_ID AS Expr3, dbo.ITEMS.CAT4_ID AS Expr4, dbo.ITEMS.CAT5_ID AS Expr5, dbo.ITEMS.CAT6_ID AS Expr6, dbo.ITEMS.CAT7_ID AS Expr7
FROM            dbo.ITEMS LEFT OUTER JOIN
                         dbo.CATEOGRY4 ON dbo.ITEMS.CAT4_ID = dbo.CATEOGRY4.CAT4_ID LEFT OUTER JOIN
                         dbo.CATEGORY2 ON dbo.ITEMS.CAT2_ID = dbo.CATEGORY2.CAT2_ID LEFT OUTER JOIN
                         dbo.CATEOGRY7 ON dbo.ITEMS.CAT7_ID = dbo.CATEOGRY7.CAT7_ID LEFT OUTER JOIN
                         dbo.CATEGORY1 ON dbo.ITEMS.CAT1_ID = dbo.CATEGORY1.CAT1_ID LEFT OUTER JOIN
                         dbo.CATEOGRY6 ON dbo.ITEMS.CAT6_ID = dbo.CATEOGRY6.CAT6_ID LEFT OUTER JOIN
                         dbo.CATEOGRY3 ON dbo.ITEMS.CAT3_ID = dbo.CATEOGRY3.CAT3_ID LEFT OUTER JOIN
                         dbo.CATEOGRY5 ON dbo.ITEMS.CAT5_ID = dbo.CATEOGRY5.CAT5_ID LEFT OUTER JOIN
                         dbo.ITEMS_SUB ON dbo.ITEMS.ITEM_ID = dbo.ITEMS_SUB.ITEM_ID;


-- dbo.ITEMS_SELECTED_VIEW source

CREATE OR ALTER VIEW [dbo].[ITEMS_SELECTED_VIEW]
AS
SELECT     dbo.ITEMS_SELECTED.BAR_ID, dbo.ITEMS_SELECTED.ITEM_ID, dbo.BARCODE.PRICE1, dbo.BARCODE.PRICE2, dbo.BARCODE.PRICE3, dbo.BARCODE.PRICE4, 
                      dbo.BARCODE.PRICE5, dbo.BARCODE.PUBLIC_PRICE, dbo.BARCODE.PRICE_LESS, dbo.BARCODE.QTY, dbo.BARCODE.PRICE_QTY, 
