-- dbo.TRANSFER_ITEMS_INVOICE_VIEW source

CREATE OR ALTER VIEW [dbo].[TRANSFER_ITEMS_INVOICE_VIEW]
AS
SELECT     dbo.TRANSFER_ITEMS.TR_ITEM_ID, dbo.TRANSFER_ITEMS.TR_ID, dbo.TRANSFER_ITEMS.ITEM_ID, dbo.TRANSFER_ITEMS.QTY, dbo.TRANSFER_ITEMS.UNIT_ID, 
                      dbo.TRANSFER_ITEMS.UNIT_QTY, dbo.TRANSFER_ITEMS.STORE_F_ID, dbo.TRANSFER_ITEMS.STORE_T_ID, dbo.TRANSFER_ITEMS.CATEOGRY1, 
                      dbo.TRANSFER_ITEMS.CATEOGRY2, dbo.TRANSFER_ITEMS.CATEOGRY3, dbo.TRANSFER_ITEMS.CAT3, dbo.TRANSFER_ITEMS.OFS, 
                      dbo.TRANSFER_INVOICE.TR_DATE, dbo.TRANSFER_INVOICE.TR_DISC, dbo.TRANSFER_INVOICE.TR_STATUES, dbo.TRANSFER_INVOICE.TR_NOTE, 
                      dbo.TRANSFER_INVOICE.USERS_ID, dbo.TRANSFER_INVOICE.TR_UPDATE_DATE, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.UNITS.UNIT_DISC, 
                      dbo.STORE_VIEW1.STORE_NAME AS STORE_NAME_F, dbo.STORE_VIEW2.STORE_NAME AS STORE_NAME_T, dbo.ITEMS.CAT1_ID, dbo.ITEMS.CAT2_ID, 
                      dbo.ITEMS.CAT3_ID, dbo.ITEMS.CAT4_ID, dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, dbo.ITEMS.CAT7_ID, dbo.TRANS_CATEGORY.TRAN_ID, 
                      dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANSFER_INVOICE.TRAN_NO, 
                      dbo.TRANSFER_INVOICE.TRAN_BARNCH
FROM         dbo.TRANS_CATEGORY RIGHT OUTER JOIN
                      dbo.TRANSFER_INVOICE ON dbo.TRANS_CATEGORY.TRAN_ID = dbo.TRANSFER_INVOICE.TRAN_ID RIGHT OUTER JOIN
                      dbo.STORE_VIEW2 RIGHT OUTER JOIN
                      dbo.TRANSFER_ITEMS ON dbo.STORE_VIEW2.STORE_ID = dbo.TRANSFER_ITEMS.STORE_T_ID LEFT OUTER JOIN
                      dbo.STORE_VIEW1 ON dbo.TRANSFER_ITEMS.STORE_F_ID = dbo.STORE_VIEW1.STORE_ID ON 
                      dbo.TRANSFER_INVOICE.TR_ID = dbo.TRANSFER_ITEMS.TR_ID LEFT OUTER JOIN
                      dbo.ITEMS ON dbo.TRANSFER_ITEMS.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                      dbo.UNITS ON dbo.TRANSFER_ITEMS.UNIT_ID = dbo.UNITS.UNIT_ID;


-- dbo.TRANSFER_ITEMS_VIEW source

CREATE OR ALTER VIEW [dbo].[TRANSFER_ITEMS_VIEW]
AS
SELECT     dbo.TRANSFER_ITEMS.TR_ITEM_ID, dbo.TRANSFER_ITEMS.TR_ID, dbo.TRANSFER_ITEMS.ITEM_ID, dbo.TRANSFER_ITEMS.QTY, 
                      dbo.TRANSFER_ITEMS.UNIT_ID, dbo.TRANSFER_ITEMS.UNIT_QTY, dbo.TRANSFER_ITEMS.STORE_F_ID, dbo.TRANSFER_ITEMS.STORE_T_ID, 
                      dbo.TRANSFER_ITEMS.CATEOGRY1, dbo.TRANSFER_ITEMS.CATEOGRY2, dbo.TRANSFER_ITEMS.CATEOGRY3, dbo.TRANSFER_ITEMS.CAT3, 
                      dbo.TRANSFER_ITEMS.OFS, dbo.UNITS.UNIT_DISC, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, 
                      dbo.STORE_VIEW2.STORE_NAME AS STORE_NAME_To, dbo.STORE_VIEW1.STORE_NAME AS STORE_NAME_From, dbo.TRANSFER_ITEMS.QTY_F, 
                      dbo.TRANSFER_ITEMS.QTY_T
FROM         dbo.TRANSFER_ITEMS LEFT OUTER JOIN
                      dbo.UNITS ON dbo.TRANSFER_ITEMS.UNIT_ID = dbo.UNITS.UNIT_ID LEFT OUTER JOIN
                      dbo.ITEMS ON dbo.TRANSFER_ITEMS.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                      dbo.STORE_VIEW2 ON dbo.TRANSFER_ITEMS.STORE_T_ID = dbo.STORE_VIEW2.STORE_ID LEFT OUTER JOIN
                      dbo.STORE_VIEW1 ON dbo.TRANSFER_ITEMS.STORE_F_ID = dbo.STORE_VIEW1.STORE_ID;


-- dbo.TRANS_CATEGORY_VIEW source

CREATE OR ALTER VIEW [dbo].[TRANS_CATEGORY_VIEW]
AS
SELECT     dbo.TRANS_CATEGORY.TRAN_ID, dbo.TRANS_CATEGORY.TRAN_DESC, dbo.TRANS_CATEGORY.TRAN_SHORT_CUT, dbo.TRANS_CATEGORY.TRAN_INVISIBLE, 
                      dbo.TRANS_CATEGORY.TRAN_UPDATE_DATE, dbo.TRANS_CATEGORY.USERS_ID, dbo.USERS.FULL_NAME, dbo.TRANS_CATEGORY.CAT1_ID, 
                      dbo.CATEGORY1.CAT1_NAME, dbo.TRANS_CATEGORY.LOGO
FROM         dbo.TRANS_CATEGORY LEFT OUTER JOIN
                      dbo.CATEGORY1 ON dbo.TRANS_CATEGORY.CAT1_ID = dbo.CATEGORY1.CAT1_ID LEFT OUTER JOIN
                      dbo.USERS ON dbo.TRANS_CATEGORY.USERS_ID = dbo.USERS.USERS_ID;


-- dbo.TRANS_ITEMS_SERIAL_NO_VIEW source

CREATE OR ALTER VIEW [dbo].[TRANS_ITEMS_SERIAL_NO_VIEW]
AS
SELECT     dbo.TR_ITEMS_SERIAL_NO.TR_S_ID, dbo.TR_ITEMS_SERIAL_NO.TR_ITEM_ID, dbo.TR_ITEMS_SERIAL_NO.SERIAL_NO, 
                      dbo.TR_ITEMS_SERIAL_NO.TR_UPDATE_DATE, dbo.TR_ITEMS_SERIAL_NO.USERS_ID, dbo.USERS.FULL_NAME, dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, 
                      dbo.TRANSFER_INVOICE.TR_DATE, dbo.TRANSFER_INVOICE.TR_DISC, dbo.TR_ITEMS_SERIAL_NO.TR_ID, dbo.TR_ITEMS_SERIAL_NO.ITEM_ID, 
                      dbo.STORE_VIEW1.STORE_NAME AS STORE_NAME1, dbo.STORE_VIEW2.STORE_NAME AS STORE_NAME2, dbo.TRANSFER_INVOICE.TR_STATUES, 
                      dbo.TRANSFER_INVOICE.TRAN_NO, dbo.TRANSFER_INVOICE.TRAN_BARNCH
FROM         dbo.STORE_VIEW2 RIGHT OUTER JOIN
                      dbo.TRANSFER_ITEMS ON dbo.STORE_VIEW2.STORE_ID = dbo.TRANSFER_ITEMS.STORE_T_ID LEFT OUTER JOIN
                      dbo.STORE_VIEW1 ON dbo.TRANSFER_ITEMS.STORE_F_ID = dbo.STORE_VIEW1.STORE_ID RIGHT OUTER JOIN
                      dbo.TR_ITEMS_SERIAL_NO LEFT OUTER JOIN
                      dbo.TRANSFER_INVOICE ON dbo.TR_ITEMS_SERIAL_NO.TR_ID = dbo.TRANSFER_INVOICE.TR_ID ON 
                      dbo.TRANSFER_ITEMS.TR_ITEM_ID = dbo.TR_ITEMS_SERIAL_NO.TR_ITEM_ID LEFT OUTER JOIN
                      dbo.ITEMS ON dbo.TR_ITEMS_SERIAL_NO.ITEM_ID = dbo.ITEMS.ITEM_ID LEFT OUTER JOIN
                      dbo.USERS ON dbo.TR_ITEMS_SERIAL_NO.USERS_ID = dbo.USERS.USERS_ID;


