                         dbo.SHORT_CUT_GROUPS.SCG_NAME, dbo.ITEMS.TYPE, dbo.ITEMS.MIN_LEVEL, dbo.ITEMS.MAX_LEVEL, dbo.BARCODE.H_W, dbo.ITEMS_IMAGES.PIC_PATH, dbo.CATEGORY1.CAT1_NAME, dbo.CATEGORY2.CAT2_NAME, 
                         dbo.CATEOGRY3.CAT3_NAME, dbo.ITEMS.NO_COST, dbo.BARCODE.SIZE, dbo.BARCODE.WAIGHT, dbo.BARCODE.COMMSION, dbo.BARCODE.COMMSION_TYPE, dbo.ITEMS.PRICE_QTY AS PRICE_QTY_FLAG
FROM            dbo.CATEGORY2 RIGHT OUTER JOIN
                         dbo.CATEOGRY3 RIGHT OUTER JOIN
                         dbo.ITEMS ON dbo.CATEOGRY3.CAT3_ID = dbo.ITEMS.CAT3_ID ON dbo.CATEGORY2.CAT2_ID = dbo.ITEMS.CAT2_ID LEFT OUTER JOIN
                         dbo.ITEMS_IMAGES ON dbo.ITEMS.ITEM_ID = dbo.ITEMS_IMAGES.ITEM_ID LEFT OUTER JOIN
                         dbo.CATEGORY1 ON dbo.ITEMS.CAT1_ID = dbo.CATEGORY1.CAT1_ID RIGHT OUTER JOIN
                         dbo.SHORT_CUT_GROUPS RIGHT OUTER JOIN
                         dbo.BARCODE ON dbo.SHORT_CUT_GROUPS.SCG_ID = dbo.BARCODE.SCG_ID ON dbo.ITEMS.ITEM_ID = dbo.BARCODE.ITEM_ID LEFT OUTER JOIN
                         dbo.USERS ON dbo.BARCODE.USERS_ID = dbo.USERS.USERS_ID LEFT OUTER JOIN
                         dbo.UNITS ON dbo.BARCODE.UNIT_ID = dbo.UNITS.UNIT_ID;


-- dbo.BUY_INVOICE_EXPENCES_VIEW source

