                      dbo.STORES ON dbo.BUY_ITEMS.STORE_ID = dbo.STORES.STORE_ID ON dbo.BUY_INVOICE.B_ID = dbo.BUY_ITEMS.B_ID RIGHT OUTER JOIN
                      dbo.USERS RIGHT OUTER JOIN
                      dbo.BUY_ITEMS_SERIAL_NO ON dbo.USERS.USERS_ID = dbo.BUY_ITEMS_SERIAL_NO.USERS_ID ON 
                      dbo.BUY_ITEMS.B_ITEM_ID = dbo.BUY_ITEMS_SERIAL_NO.B_ITEM_ID ON dbo.ITEMS.ITEM_ID = dbo.BUY_ITEMS_SERIAL_NO.ITEM_ID LEFT OUTER JOIN
                      dbo.CUSTOMERS ON dbo.BUY_INVOICE.CUST_ID = dbo.CUSTOMERS.CUST_ID;


