                         dbo.SALE_ITEMS_DELETED.UNIT_ID, dbo.SALE_ITEMS_DELETED.UNIT_QTY, dbo.SALE_ITEMS_DELETED.CATEOGRY1, dbo.SALE_ITEMS_DELETED.CATEOGRY2, dbo.SALE_ITEMS_DELETED.CATEOGRY3, 
