                      dbo.CURRENCY ON dbo.BUY_ITEMS.CURRENCY_ID = dbo.CURRENCY.CURRENCY_ID LEFT OUTER JOIN
                      dbo.UNITS ON dbo.BUY_ITEMS.UNIT_ID = dbo.UNITS.UNIT_ID ON dbo.ITEMS.ITEM_ID = dbo.BUY_ITEMS.ITEM_ID ON 
                      dbo.BUY_INVOICE.B_ID = dbo.BUY_ITEMS.B_ID;


