                         dbo.ITEMS.CAT1_ID, dbo.ITEMS.CAT2_ID, dbo.ITEMS.CAT3_ID, dbo.ITEMS.CAT4_ID, dbo.ITEMS.CAT5_ID, dbo.ITEMS.CAT6_ID, dbo.ITEMS.CAT7_ID, 
                         dbo.C_BUY_ITEMS.ITEM_ID, dbo.C_BUY_ITEMS.CB_ID, dbo.CUSTOMERS.CAT8_ID, dbo.C_BUY_INVOICE.CUST_ID, dbo.C_BUY_ITEMS.QTY, 
                         dbo.C_BUY_ITEMS.UNIT_ID, dbo.C_BUY_ITEMS.UNIT_QTY, dbo.C_BUY_ITEMS.CATEOGRY1, dbo.C_BUY_ITEMS.CATEOGRY2, dbo.C_BUY_ITEMS.CATEOGRY3, 
                         dbo.C_BUY_ITEMS.PRICE, dbo.C_BUY_INVOICE.CB_STATUES, dbo.CUSTOMERS.REGION_ID, dbo.C_BUY_INVOICE.CB_ARRIVE_DATE, 
