                         dbo.ITEMS.ITEM_MODEL, dbo.ITEMS.ITEM_NAME, dbo.UNITS.UNIT_DISC, dbo.STORES.STORE_NAME, dbo.USERS.FULL_NAME, dbo.SALE_INVOICE.S_ID AS Expr1, dbo.SALE_INVOICE.S_DATE, 
                         dbo.SALE_INVOICE.CUST_ID, dbo.SALE_INVOICE.COMM_ID, dbo.SALE_INVOICE.TRAN_NO, dbo.SALE_INVOICE.TRAN_BARNCH
