                         dbo.R_S_INVOICE ON dbo.USERS.USERS_ID = dbo.R_S_INVOICE.A_USERS_ID LEFT OUTER JOIN
                         dbo.CUSTOMERS ON dbo.R_S_INVOICE.CUST_ID = dbo.CUSTOMERS.CUST_ID LEFT OUTER JOIN
                         dbo.COMMISSIONER ON dbo.R_S_INVOICE.COMM_ID = dbo.COMMISSIONER.COMM_ID LEFT OUTER JOIN
                         dbo.BANKS ON dbo.R_S_INVOICE.BANK_ID = dbo.BANKS.BANK_ID LEFT OUTER JOIN
                         dbo.TRANS_CATEGORY ON dbo.R_S_INVOICE.TRAN_ID = dbo.TRANS_CATEGORY.TRAN_ID LEFT OUTER JOIN
                         dbo.ACC_CREDIT ON dbo.R_S_INVOICE.ACC_CREDIT = dbo.ACC_CREDIT.AC_ID LEFT OUTER JOIN
                         dbo.ACC_DEBIT ON dbo.R_S_INVOICE.ACC_DEBIT = dbo.ACC_DEBIT.AC_ID LEFT OUTER JOIN
                         dbo.TYPE ON dbo.R_S_INVOICE.S_R_STATUES = dbo.TYPE.T_ID LEFT OUTER JOIN
                         dbo.USERS AS USERS_1 ON dbo.R_S_INVOICE.USERS_ID = USERS_1.USERS_ID;


