                      dbo.R_S_ITEMS.UNIT_ID, dbo.R_S_ITEMS.UNIT_QTY, dbo.R_S_ITEMS.CATEOGRY1, dbo.R_S_ITEMS.CATEOGRY2, dbo.R_S_ITEMS.CATEOGRY3, 
