CREATE OR ALTER VIEW [dbo].[WORK_TABLE_VIEW]
AS
SELECT     SALES, SALES_COST, BUYS, R_SALES, R_SALES_COST, R_BUYS, SPOILS, USER_NAMES, SPENDS, TAKES, GIVES
FROM         dbo.WORK_TABLE;